import{_ as t,o as a,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Add & Manage Agency Users","description":"","frontmatter":{"title":"Add & Manage Agency Users","slug":"add-agency-users"},"headers":[],"relativePath":"account-hub/add-agency-users.md","filePath":"account-hub/add-agency-users.md"}'),r={name:"account-hub/add-agency-users.md"};function s(i,e,c,l,d,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<p>Agency admins have the ability to add other users to their agency. To complete the steps below, be sure you&#39;re in the agency record, not the app.</p><h2 id="add-new-agency-users-to-your-team" tabindex="-1">Add New Agency Users to Your Team <a class="header-anchor" href="#add-new-agency-users-to-your-team" aria-label="Permalink to &quot;Add New Agency Users to Your Team&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Agency users</p><p>Agency users are managed by agencies. Agencies themselves add members within their view. Please make sure you are in your Agency account in the Branch Dashboard, not the client&#39;s Branch app account.</p></div><ol><li><p>From the Branch Dashboard, navigate to the <a href="https://dashboard.branch.io/account-settings" target="_blank" rel="noreferrer">Account Settings</a> page in the Dashboard, and click the <a href="https://branch.dashboard.branch.io/account-settings/team" target="_blank" rel="noreferrer">Team</a> tab.</p></li><li><p>Click the <strong>Add Agency Team Member</strong> button.</p></li><li><p>Complete the following fields:</p><ul><li><p>Email Address</p></li><li><p>First Name</p></li><li><p>Last Name</p></li><li><p>Select the <strong>Access Level</strong> you wish to grant the user, your options are:</p><ul><li><strong>Agency Admin</strong> - This grants full access to the Account Settings tab, including the ability to add, edit, and remove agency team members.</li><li><strong>Agency Team Member</strong> - Read-only access on the Account Settings tab.</li></ul></li></ul></li><li><p>Click <strong>Invite</strong> when you&#39;re done.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Disabled Functionality</p><p>Any restricted functionality - either due to default Agency restrictions or selected access levels - in the Branch dashboard will be (1) grayed out, (2) not clickable, (3) include a pop up modal informing the user about restricted access. See more about <a href="./add-agency-to-your-account.html#section-default-agency-access-level-restrictions">default agency restrictions</a>.</p></div><h2 id="manage-agency-users" tabindex="-1">Manage Agency Users <a class="header-anchor" href="#manage-agency-users" aria-label="Permalink to &quot;Manage Agency Users&quot;">​</a></h2><h3 id="modifying-permissions-of-an-existing-team-member" tabindex="-1">Modifying Permissions of an Existing Team Member <a class="header-anchor" href="#modifying-permissions-of-an-existing-team-member" aria-label="Permalink to &quot;Modifying Permissions of an Existing Team Member&quot;">​</a></h3><p>To modify an existing agency team member:</p><ol><li>On the <a href="https://branch.dashboard.branch.io/account-settings" target="_blank" rel="noreferrer">Account Settings</a> page, on the <a href="https://dashboard.branch.io/account-settings/agencies" target="_blank" rel="noreferrer">Agencies</a> tab, find the team member you want to modify and click the <code>...</code> button in the Actions column for that user.</li><li>Click Edit to modify the agency team member.</li><li>Click <strong>Save</strong> when you&#39;re done.</li></ol><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>To change the email address associated with an existing agency team member, please contact <a href="https://support.branch.io/hc/en-us/requests/new" target="_blank" rel="noreferrer">Support</a>.</p></div><h3 id="resend-invitation-to-join" tabindex="-1">Resend Invitation to Join <a class="header-anchor" href="#resend-invitation-to-join" aria-label="Permalink to &quot;Resend Invitation to Join&quot;">​</a></h3><p>To resend the invitation to join the account:</p><ol><li>On the <a href="https://branch.dashboard.branch.io/account-settings" target="_blank" rel="noreferrer">Account Settings</a> page, on the <a href="https://dashboard.branch.io/account-settings/agencies" target="_blank" rel="noreferrer">Agencies</a> tab, find the team member you want to resend the invite to.</li><li>Click on the <code>...</code> and click <strong>Resend Invite</strong>.</li></ol><h3 id="delete-team-member" tabindex="-1">Delete Team Member <a class="header-anchor" href="#delete-team-member" aria-label="Permalink to &quot;Delete Team Member&quot;">​</a></h3><ol><li>On the <a href="https://branch.dashboard.branch.io/account-settings" target="_blank" rel="noreferrer">Account Settings</a> page, on the <a href="https://dashboard.branch.io/account-settings/agencies" target="_blank" rel="noreferrer">Agencies</a> tab, find the team member you want to delete.</li><li>Click on the <code>...</code></li><li>Click <strong>Delete</strong>.</li><li>In the <strong>Are you sure you want to delete?</strong> modal, click <strong>Yes, Delete</strong>.</li></ol><h3 id="request-additional-permissions" tabindex="-1">Request Additional Permissions <a class="header-anchor" href="#request-additional-permissions" aria-label="Permalink to &quot;Request Additional Permissions&quot;">​</a></h3><p>As a non-Admin user, you may not be able to access/use certain sections of the Branch dashboard. If you’d like more access, please contact your Agency Admin user on the account to ask for more permissions.</p>',17)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
